# Kotlin/Android 项目中集成多家大模型 API 的最佳实践指南

根据我的研究，以下是全面的集成指南，包括国内外主要大模型 API 的调用方式、官方文档链接和代码示例。

---

## 1. 国内大模型 API 集成

### 1.1 百度文心一言 (ERNIE Bot)

**官方文档链接：**
- [千帆大模型平台官方文档](https://cloud.baidu.com/doc/qianfan/index.html)
- [AI Studio API 文档](https://ai.baidu.com/ai-doc/AISTUDIO/rm344erns)
- [千帆平台 SDK 文档](https://qianfan.readthedocs.io/)

**基本调用示例（使用 OkHttp）：**

```kotlin
import okhttp3.*
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.RequestBody.Companion.toRequestBody
import org.json.JSONArray
import org.json.JSONObject
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext

class WenxinClient(private val apiKey: String, private val secretKey: String) {

    private val client = OkHttpClient()
    private val JSON = "application/json; charset=utf-8".toMediaType()

    // 获取 Access Token
    private suspend fun getAccessToken(): String = withContext(Dispatchers.IO) {
        val request = Request.Builder()
            .url("https://aip.baidubce.com/oauth/2.0/token?grant_type=client_credentials&client_id=$apiKey&client_secret=$secretKey")
            .build()

        val response = client.newCall(request).execute()
        val jsonResponse = JSONObject(response.body?.string())
        jsonResponse.getString("access_token")
    }

    // 调用文心一言 API
    suspend fun chat(prompt: String): String = withContext(Dispatchers.IO) {
        val accessToken = getAccessToken()

        val jsonBody = JSONObject().apply {
            put("messages", JSONArray().apply {
                put(JSONObject().apply {
                    put("role", "user")
                    put("content", prompt)
                })
            })
        }

        val request = Request.Builder()
            .url("https://aip.baidubce.com/rpc/2.0/ai_custom/v1/wenxinworkshop/chat/completions?access_token=$accessToken")
            .post(jsonBody.toString().toRequestBody(JSON))
            .build()

        val response = client.newCall(request).execute()
        val jsonResponse = JSONObject(response.body?.string())
        jsonResponse.getString("result")
    }
}
```

