## 3. 并行调用模式

### 3.1 使用 Kotlin Coroutines 实现并行调用

```kotlin
import kotlinx.coroutines.*
import kotlinx.coroutines.tasks.await

data class LLMResponse(
    val provider: String,
    val response: String,
    val latency: Long,
    val success: Boolean,
    val error: Throwable? = null
)

class MultiLLMOrchestrator(
    private val openAIClient: OpenAIClient,
    private val claudeClient: ClaudeClient,
    private val geminiClient: GeminiClient,
    private val qwenClient: QwenClient,
    private val wenxinClient: WenxinClient,
    private val zhipuClient: ZhipuClient
) {

    suspend fun chatAllProviders(prompt: String): List<LLMResponse> = coroutineScope {
        val startTime = System.currentTimeMillis()

        // 并行调用所有 LLM
        val results = listOf(
            async { callLLM("OpenAI") { openAIClient.chat(prompt) } },
            async { callLLM("Claude") { claudeClient.chat(prompt) } },
            async { callLLM("Gemini") { geminiClient.chat(prompt) } },
            async { callLLM("Qwen") { qwenClient.chat(prompt) } },
            async { callLLM("Wenxin") { wenxinClient.chat(prompt) } },
            async { callLLM("Zhipu") { zhipuClient.chat(prompt) } }
        ).awaitAll()

        results
    }

    private suspend fun callLLM(
        provider: String,
        block: suspend () -> String
    ): LLMResponse {
        val startTime = System.currentTimeMillis()
        return try {
            val response = block()
            val latency = System.currentTimeMillis() - startTime
            LLMResponse(provider, response, latency, true)
        } catch (e: Exception) {
            val latency = System.currentTimeMillis() - startTime
            LLMResponse(provider, "", latency, false, e)
        }
    }
}
```

