### 3.3 使用 SupervisorJob 实现独立错误处理

```kotlin
import kotlinx.coroutines.*
import kotlinx.coroutines.supervisorScope

class ResilientLLMOrchestrator(
    private val clients: List<LLMClient>
) {

    suspend fun fetchWithResilience(
        prompt: String
    ): Map<String, LLMResponse> = supervisorScope {

        val results = mutableMapOf<String, LLMResponse>()

        clients.forEach { client ->
            launch {
                try {
                    val response = client.chat(prompt)
                    results[client.providerName] = LLMResponse(
                        provider = client.providerName,
                        response = response,
                        latency = 0,
                        success = true
                    )
                } catch (e: Exception) {
                    results[client.providerName] = LLMResponse(
                        provider = client.providerName,
                        response = "",
                        latency = 0,
                        success = false,
                        error = e
                    )
                }
            }
        }

        // 等待所有请求完成（无论成功或失败）
        currentCoroutineContext().job.children.forEach { it.join() }

        results
    }
}

interface LLMClient {
    val providerName: String
    suspend fun chat(prompt: String): String
}
