### 3.4 多个异步请求的结果对比

```kotlin
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.*

data class ComparisonResult(
    val prompt: String,
    val responses: List<LLMResponse>,
    val fastest: LLMResponse?,
    val allSuccessful: Boolean,
    val consensus: String?
)

class LLMComparator(
    private val orchestrator: MultiLLMOrchestrator
) {

    suspend fun compareResponses(prompt: String): ComparisonResult {
        val responses = orchestrator.chatAllProviders(prompt)

        val successful = responses.filter { it.success }
        val fastest = successful.minByOrNull { it.latency }
        val allSuccessful = responses.size == successful.size

        // 简单的共识算法：选择最相似的两个响应
        val consensus = findConsensus(successful.map { it.response })

        return ComparisonResult(
            prompt = prompt,
            responses = responses,
            fastest = fastest,
            allSuccessful = allSuccessful,
            consensus = consensus
        )
    }

    private fun findConsensus(responses: List<String>): String? {
        if (responses.isEmpty()) return null
        if (responses.size == 1) return responses[0]

        // 简单的相似度计算（实际应用中可以使用更复杂的算法）
        val similarities = responses.mapIndexed { i, response1 ->
            responses.mapIndexedNotNull { j, response2 ->
                if (i < j) {
                    val similarity = calculateSimilarity(response1, response2)
                    i to j to similarity
                } else null
            }
        }.flatten()

        val bestPair = similarities.maxByOrNull { it.third }
        return bestPair?.let { responses[it.first.second] }
    }

    private fun calculateSimilarity(s1: String, s2: String): Double {
        val words1 = s1.split(" ").toSet()
        val words2 = s2.split(" ").toSet()
        val intersection = words1.intersect(words2)
        val union = words1.union(words2)
        return if (union.isEmpty()) 0.0 else intersection.size.toDouble() / union.size
    }
}
