### 3.5 完整的并行调用架构

```kotlin
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.*

/**
 * 统一的 LLM 提供商接口
 */
interface LLMProvider {
    val name: String
    val priority: Int // 用于回退策略
    suspend fun generate(prompt: String): Result<String>
}

/**
 * 并行 LLM 调用管理器
 */
class ParallelLLMManager(
    private val providers: List<LLMProvider>,
    private val defaultTimeout: Duration = 30.seconds
) {

    /**
     * 并行调用所有提供商
     */
    suspend fun callAll(
        prompt: String,
        timeout: Duration = defaultTimeout
    ): List<ProviderResult> = coroutineScope {

        providers.map { provider ->
            async(Dispatchers.IO) {
                val startTime = System.currentTimeMillis()
                try {
                    withTimeout(timeout) {
                        val result = provider.generate(prompt)
                        val latency = System.currentTimeMillis() - startTime
                        ProviderResult(
                            provider = provider.name,
                            response = result.getOrNull(),
                            latency = latency,
                            success = result.isSuccess,
                            error = result.exceptionOrNull()
                        )
                    }
                } catch (e: TimeoutCancellationException) {
                    ProviderResult(
                        provider = provider.name,
                        response = null,
                        latency = timeout.inWholeMilliseconds,
                        success = false,
                        error = e
                    )
                } catch (e: Exception) {
                    ProviderResult(
                        provider = provider.name,
                        response = null,
                        latency = System.currentTimeMillis() - startTime,
                        success = false,
                        error = e
                    )
                }
            }
        }.awaitAll()
    }

    /**
     * 竞速模式：返回第一个成功的响应
     */
    suspend fun race(
        prompt: String,
        timeout: Duration = defaultTimeout
    ): ProviderResult? = coroutineScope {

        val deferred = providers.map { provider ->
            async(Dispatchers.IO) {
                val startTime = System.currentTimeMillis()
                try {
                    withTimeout(timeout) {
                        val result = provider.generate(prompt)
                        val latency = System.currentTimeMillis() - startTime
                        ProviderResult(
                            provider = provider.name,
                            response = result.getOrNull(),
                            latency = latency,
                            success = result.isSuccess,
                            error = result.exceptionOrNull()
                        )
                    }
                } catch (e: Exception) {
                    null
                }
            }
        }

        // 返回第一个成功的响应
        deferred.mapNotNull { 
            it.await() 
        }.firstOrNull { it.success }
    }

    /**
     * 回退模式：按优先级依次尝试
     */
    suspend fun fallback(
        prompt: String,
        timeout: Duration = defaultTimeout
    ): ProviderResult? {

        val sortedProviders = providers.sortedBy { it.priority }

        for (provider in sortedProviders) {
            try {
                withTimeout(timeout) {
                    val result = provider.generate(prompt)
                    if (result.isSuccess) {
                        return ProviderResult(
                            provider = provider.name,
                            response = result.getOrNull(),
                            latency = 0,
                            success = true,
                            error = null
                        )
                    }
                }
            } catch (e: Exception) {
                // 继续尝试下一个提供商
                continue
            }
        }

        return null
    }

    /**
     * Flow 模式：实时返回结果
     */
    fun streamResults(
        prompt: String,
        timeout: Duration = defaultTimeout
    ): Flow<ProviderResult> = flow {

        providers.forEach { provider ->
            try {
                withTimeout(timeout) {
                    val startTime = System.currentTimeMillis()
                    val result = provider.generate(prompt)
                    val latency = System.currentTimeMillis() - startTime

                    emit(
                        ProviderResult(
                            provider = provider.name,
                            response = result.getOrNull(),
                            latency = latency,
                            success = result.isSuccess,
                            error = result.exceptionOrNull()
                        )
                    )
                }
            } catch (e: Exception) {
                emit(
                    ProviderResult(
                        provider = provider.name,
                        response = null,
                        latency = timeout.inWholeMilliseconds,
                        success = false,
                        error = e
                    )
                )
            }
        }
    }.flowOn(Dispatchers.IO)
}

data class ProviderResult(
    val provider: String,
    val response: String?,
    val latency: Long,
    val success: Boolean,
    val error: Throwable?
)
