### 3.6 在 Android ViewModel 中使用

```kotlin
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.launch
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.catch

class ChatViewModel(
    private val llmManager: ParallelLLMManager
) : ViewModel() {

    private val _uiState = MutableStateFlow<ChatUiState>(ChatUiState.Idle)
    val uiState = _uiState.asStateFlow()

    fun sendMessage(message: String) {
        viewModelScope.launch {
            _uiState.value = ChatUiState.Loading

            try {
                // 使用竞速模式
                val result = llmManager.race(message)

                if (result != null && result.success) {
                    _uiState.value = ChatUiState.Success(
                        result.response ?: "Empty response",
                        result.provider,
                        result.latency
                    )
                } else {
                    // 竞速失败，尝试并行调用所有
                    val allResults = llmManager.callAll(message)
                    val firstSuccess = allResults.firstOrNull { it.success }

                    if (firstSuccess != null) {
                        _uiState.value = ChatUiState.Success(
                            firstSuccess.response ?: "Empty response",
                            firstSuccess.provider,
                            firstSuccess.latency
                        )
                    } else {
                        _uiState.value = ChatUiState.Error("All providers failed")
                    }
                }
            } catch (e: Exception) {
                _uiState.value = ChatUiState.Error(e.message ?: "Unknown error")
            }
        }
    }

    fun compareProviders(message: String) {
        viewModelScope.launch {
            _uiState.value = ChatUiState.Loading

            try {
                val results = llmManager.callAll(message)
                _uiState.value = ChatUiState.Comparison(results)
            } catch (e: Exception) {
                _uiState.value = ChatUiState.Error(e.message ?: "Unknown error")
            }
        }
    }

    fun streamResponses(message: String) {
        viewModelScope.launch {
            _uiState.value = ChatUiState.Loading

            llmManager.streamResults(message)
                .catch { e ->
                    _uiState.value = ChatUiState.Error(e.message ?: "Stream error")
                }
                .collect { result ->
                    _uiState.value = ChatUiState.StreamingResult(result)
                }
        }
    }
}

sealed class ChatUiState {
    object Idle : ChatUiState()
    object Loading : ChatUiState()
    data class Success(val response: String, val provider: String, val latency: Long) : ChatUiState()
    data class Error(val message: String) : ChatUiState()
    data class Comparison(val results: List<ProviderResult>) : ChatUiState()
    data class StreamingResult(val result: ProviderResult) : ChatUiState()
}
